TAXONOMY=CONFIG/'phase7_3_3_d_failure_taxonomy_v2.json'; V1_PROTOCOL=CONFIG/'phase7_3_3_d_multi_claim_successor_support_review_protocol_v1.json'; V1_SCHEMA=CONFIG/'phase7_3_3_d_multi_claim_successor_support_review_schema_v1.json'; V1_POLICY=CONFIG/'phase7_3_3_d_multi_claim_successor_support_review_execution_policy_v1.json'; V1_PROMPT=CONFIG/'phase7_3_3_d_multi_claim_successor_support_reviewer_prompt_v1.md'; V1_ADAPTER=ROOT/'scripts/eval/phase7_multi_claim_successor_support_review_v1.py'
