def hb(b:bytes)->str:return hashlib.sha256(b).hexdigest()
def sha(p:Path)->str:return hb(p.read_bytes())
def load(p:Path)->Any:return json.loads(p.read_text(encoding='utf-8-sig'))
def rel(p:Path)->str:return p.relative_to(ROOT).as_posix()
def jb(x:Any)->bytes:return (json.dumps(x,ensure_ascii=False,indent=2)+'\n').encode()
def once(p:Path,b:bytes)->str:
 if p.exists():
  if p.read_bytes()!=b:raise ValueError('immutable_artifact_mismatch:'+rel(p))
  return hb(b)
 p.parent.mkdir(parents=True,exist_ok=True)
 with tempfile.NamedTemporaryFile('wb',dir=p.parent,delete=False) as f:f.write(b);t=Path(f.name)
 t.replace(p);return hb(b)
def outputs():return [ENTRY_PROTOCOL,CLASSIFICATION,ENTRY_MANIFEST,ENTRY_OUTCOME,STATE_OUT,READY_OUT,ENTRY_RECEIPT]

def preflight()->dict[str,Any]:
 missing=[rel(p) for p in EXPECTED if not p.exists()]; mismatch={rel(p):{'expected':h,'actual':sha(p)} for p,h in EXPECTED.items() if p.exists() and sha(p)!=h}
 s=load(STATE_IN) if STATE_IN.exists() else {}; r=load(READY_IN) if READY_IN.exists() else {}; n=load(NEGATIVE) if NEGATIVE.exists() else {}; o=load(V1_OUTCOME) if V1_OUTCOME.exists() else {}; a=load(A_SUBMISSION) if A_SUBMISSION.exists() else {}
 checks={'inputs_present':not missing,'input_hashes_match':not mismatch,'entry_gate':s.get('next_authorized_stage')=='design_new_multi_claim_successor_support_review_version_if_research_continues' and r.get('next_authorized_stage')=='design_new_multi_claim_successor_support_review_version_if_research_continues','v1_authoritative_negative':n.get('status')=='authoritative_negative_result' and o.get('agreement_authorized') is False,'failure_exact':n.get('failure_level')=='level_2_support_contract' and n.get('failure_subtype')=='provenance_failure' and n.get('failure_code')=='cited_evidence_index_out_of_range','same_version_retry_forbidden':n.get('same_version_retry_allowed') is False,'a_v1_preserved':a.get('completed') is True and a.get('support_decision_count')==240,'confirmatory_closed':s.get('confirmatory_dataset_opened') is False and r.get('confirmatory_dataset_opened') is False,'runtime_unauthorized':s.get('runtime_integration_authorized') is False and r.get('runtime_integration_authorized') is False,'outputs_absent':all(not p.exists() for p in outputs())}
 return {'status':'PASS' if all(checks.values()) else 'FAIL','checks':checks,'missing':missing,'mismatches':mismatch}

def build()->dict[Path,bytes]:
 n=load(NEGATIVE)
 protocol={'schema_version':1,'protocol_id':'phase7.3.3-d-multi-claim-successor-support-review-v2-entry-protocol-v1','status':'prospectively_frozen_successor_authorization','predecessor_result':'reviewer_b_v1_authoritative_level_2_provenance_failure','predecessor_negative_result_sha256':sha(NEGATIVE),'same_version_retry_authorized':False,'successor_version':'support_review_v2','successor_hypothesis':'a fixed-length positionwise evidence-citation mask can remove the v1 out-of-range sparse-index provenance failure without changing Support semantics','controlled_invariants':['selected_40_cases','sealed_240_claim_reference_candidate','support_packets','support_labels','reason_codes','support_semantics','provider','reviewer_models','temperature','top_p','max_tokens','blindness'],'single_intended_experimental_change':'replace model-generated sparse cited_evidence_indices with a fixed-length binary evidence_citation_mask that the adapter deterministically maps to immutable evidence IDs','nonsemantic_instrumentation_correction':'propagate already-computed provider envelope/content/model hashes into any post-parse contract failure artifact','reviewer_a_v1_reused_as_v2_submission':False,'reviewer_a_and_b_v2_both_must_run_under_v2':True,'v1_artifacts_modified':False,'confirmatory_opening_authorized':False,'runtime_integration_authorized':False}
 classification={'schema_version':1,'classification_id':'phase7.3.3-d-multi-claim-successor-support-reviewer-b-failure-classification-v1','status':'frozen_authoritative_negative_result_classification','taxonomy_sha256':sha(TAXONOMY),'negative_result_sha256':sha(NEGATIVE),'primary_failure':{'level':2,'code':'support_reference_contract','subclass':'provenance','subtype':'cited_evidence_index_out_of_range'},'failure_attribution':{'primary':'provider','subtype':'returned_sparse_evidence_index_outside_public_frozen_case_domain','confidence':'high','evidence':['the public v1 prompt required one-based evidence_index values from the supplied case only','37 cases and 222 decisions completed before the first failing response','the parser rejected cited_evidence_index_out_of_range under the frozen v1 contract'],'counterevidence':['v1 failure instrumentation did not propagate the parsed content hash into the negative artifact even though an envelope was received','the evidence does not distinguish model generation from an intermediary content transformation']},'delivery_transport':'PASS after one resumable timeout','support_semantic_capability':'assessable_and_failed_for_frozen_provenance_contract_only','general_support_reasoning_capability_conclusion_authorized':False,'agreement':'not_authorized','same_version_retry_authorized':False,'observed_completed_case_count_before_failure':n.get('completed_case_count_before_failure')}
 pb=jb(protocol); cb=jb(classification); fixed={ENTRY_PROTOCOL:pb,CLASSIFICATION:cb}; fh={rel(p):hb(b) for p,b in fixed.items()}
 manifest={'schema_version':1,'manifest_id':'phase7.3.3-d-multi-claim-successor-support-review-v2-entry-manifest-v1','status':'frozen_before_v2_adapter_construction','adapter':rel(Path(__file__)),'adapter_sha256':sha(Path(__file__)),'input_sha256':{rel(p):sha(p) for p in EXPECTED},'artifact_sha256':fh,'provider_called':False,'confirmatory_dataset_opened':False,'runtime_integration_authorized':False}; mb=jb(manifest)
 outcome={'schema_version':1,'outcome_id':'phase7.3.3-d-multi-claim-successor-support-review-v2-entry-outcome-v1','status':'support_review_v2_successor_authorized','same_version_retry_performed':False,'v1_negative_result_preserved':True,'next_authorized_stage':NEXT,'confirmatory_dataset_opened':False,'runtime_integration_authorized':False}
 lineage={'multi_claim_successor_support_reviewer_b_failure_classification_v1_sha256':hb(cb),'multi_claim_successor_support_review_v2_entry_protocol_v1_sha256':hb(pb),'multi_claim_successor_support_review_v2_entry_manifest_v1_sha256':hb(mb)}
 s=copy.deepcopy(load(STATE_IN));s.setdefault('artifact_lineage',{}).update(lineage);s.update({'schema_version':53,'state_id':'phase7.3.3-d-support-stage-state-v53','status':'multi_claim_successor_support_review_v2_successor_authorized','next_authorized_stage':NEXT,'multi_claim_successor_support_review_v1_negative_preserved':True,'multi_claim_successor_support_review_v2_authorized':True,'multi_claim_successor_support_review_v2_provider_called':False,'multi_claim_successor_support_agreement_authorized':False,'confirmatory_opening_authorized':False,'confirmatory_dataset_opened':False,'runtime_integration_authorized':False})
 r=copy.deepcopy(load(READY_IN));r.setdefault('artifact_lineage',{}).update(lineage);r.update({'schema_version':64,'readiness_id':'phase7.3.3-d1-reference-construction-readiness-v64','status':'multi_claim_successor_support_review_v2_successor_authorized','next_authorized_stage':NEXT,'multi_claim_successor_support_review_v1_negative_preserved':True,'multi_claim_successor_support_review_v2_authorized':True,'provider_called':False,'multi_claim_successor_support_agreement_authorized':False,'confirmatory_opening_authorized':False,'confirmatory_dataset_opened':False,'runtime_integration_authorized':False})
 return {**fixed,ENTRY_MANIFEST:mb,ENTRY_OUTCOME:jb(outcome),STATE_OUT:jb(s),READY_OUT:jb(r)}

def freeze()->dict[str,Any]:
 q=preflight()
 if q['status']!='PASS':raise ValueError('support_review_v2_entry_preflight_failed')
 made=build(); hashes={rel(p):once(p,b) for p,b in made.items()}; receipt={'schema_version':1,'receipt_id':'phase7.3.3-d-multi-claim-successor-support-review-v2-entry-receipt-v1','status':'PASS','artifact_sha256':hashes,'same_version_retry_performed':False,'v1_negative_result_preserved':True,'provider_called':False,'confirmatory_dataset_opened':False,'runtime_integration_authorized':False,'next_authorized_stage':NEXT}; rh=once(ENTRY_RECEIPT,jb(receipt));return {'status':'PASS','classification_sha256':sha(CLASSIFICATION),'entry_manifest_sha256':sha(ENTRY_MANIFEST),'receipt_sha256':rh,'state_sha256':sha(STATE_OUT),'readiness_sha256':sha(READY_OUT),'next_authorized_stage':NEXT}
def verify()->dict[str,Any]:
 exp=build(); checks={rel(p):p.exists() and p.read_bytes()==b for p,b in exp.items()};checks[rel(ENTRY_RECEIPT)]=ENTRY_RECEIPT.exists() and load(ENTRY_RECEIPT).get('status')=='PASS';s=load(STATE_OUT) if STATE_OUT.exists() else {};r=load(READY_OUT) if READY_OUT.exists() else {};checks.update({'state_gate':s.get('next_authorized_stage')==NEXT,'readiness_gate':r.get('next_authorized_stage')==NEXT,'v1_negative_unchanged':sha(NEGATIVE)==EXPECTED[NEGATIVE],'same_version_retry_not_performed':load(ENTRY_OUTCOME).get('same_version_retry_performed') is False,'provider_not_called':s.get('multi_claim_successor_support_review_v2_provider_called') is False,'confirmatory_closed':s.get('confirmatory_dataset_opened') is False,'runtime_unauthorized':s.get('runtime_integration_authorized') is False});failed=[k for k,v in checks.items() if not v];return {'status':'PASS' if not failed else 'FAIL','checks':len(checks),'failed':failed,'next_authorized_stage':s.get('next_authorized_stage')}
def main()->int:
 p=argparse.ArgumentParser();g=p.add_mutually_exclusive_group(required=True);g.add_argument('--preflight',action='store_true');g.add_argument('--freeze',action='store_true');g.add_argument('--verify',action='store_true');a=p.parse_args();x=preflight() if a.preflight else freeze() if a.freeze else verify();print(json.dumps(x,ensure_ascii=False,indent=2));return 0 if x.get('status')=='PASS' else 1
